mapper.select:
/* USE : StoreSoldOutHistoryMapper.getSearchSoldOutHistory */

SELECT  A.STORE_CD                                                                  AS STORE_CD
,       A.STORE_NM                                                                  AS STORE_NM
,       A.PROD_CD                                                                   AS PROD_CD
,       A.PROD_NM                                                                   AS PROD_NM
,       TO_CHAR(TO_DATE(A.SOLD_OUT_Y,'YYYYMMDDHH24MISS'), 'YYYY-MM-DD HH24:MI:SS')  AS SOLD_OUT_DT
,       TO_CHAR(TO_DATE(A.SOLD_OUT_N,'YYYYMMDDHH24MISS'), 'YYYY-MM-DD HH24:MI:SS')  AS SOLD_DT

FROM    (
            SELECT  A.STORE_CD
            ,       B.STORE_NM
            ,       A.PROD_CD
            ,       C.PROD_NM
            ,       A.SOLD_OUT_DT   AS PROC_DT
            ,       CASE WHEN NVL(A.B_SOLD_OUT_YN, 'N') = 'N' AND NVL(A.SOLD_OUT_YN, 'N') = 'Y' THEN A.SOLD_OUT_DT ELSE '' END AS SOLD_OUT_Y
            ,       CASE WHEN NVL(A.B_SOLD_OUT_YN, 'N') = 'Y' AND NVL(A.SOLD_OUT_YN, 'N') = 'N' THEN A.SOLD_OUT_DT ELSE '' END AS SOLD_OUT_N
            FROM    TB_LG_PRODUCT_SOLD_OUT_HISTORY A
            ,       TB_MS_STORE B
            ,       TB_MS_PRODUCT C
            ,		TB_MS_STORE_INFO D
            WHERE   1=1
            AND     B.STORE_CD      =   A.STORE_CD
            AND     C.STORE_CD      =   A.STORE_CD
            AND     C.PROD_CD       =   A.PROD_CD
            AND    	D.STORE_CD 	(+) =	A.STORE_CD
            AND     A.STORE_CD      IN (SELECT STORE_CD FROM TB_MS_STORE WHERE HQ_OFFICE_CD = #{hqOfficeCd})
            AND     A.SYS_DATE      BETWEEN #{startDate}    AND #{endDate}
            AND     A.SOLD_OUT_FG   =   '1'

                AND A.STORE_CD IN (${storeCdQuery})


                AND A.PROD_CD IN (${prodCdQuery})


                AND B.HQ_BRAND_CD = #{storeHqBrandCd} -- 매장브랜드 선택일때



                    -- 매장브랜드 전체일때
                    AND B.HQ_BRAND_CD IN

                        #{item}




                AND C.HQ_BRAND_CD = #{prodHqBrandCd} -- 상품브랜드 선택일때



                    -- 상품브랜드 전체일때
                    AND C.HQ_BRAND_CD IN

                        #{item}




                AND C.PROD_CLASS_CD IN

                    #{item}



                AND D.MOMS_TEAM = #{momsTeam}


                AND D.MOMS_AC_SHOP = #{momsAcShop}


                AND D.MOMS_AREA_FG = #{momsAreaFg}


                AND D.MOMS_COMMERCIAL = #{momsCommercial}


                AND D.MOMS_SHOP_TYPE = #{momsShopType}


                AND D.MOMS_STORE_MANAGE_TYPE = #{momsStoreManageType}


                AND B.BRANCH_CD = #{branchCd}


                AND D.MOMS_STORE_FG_01 = #{momsStoreFg01}


                AND D.MOMS_STORE_FG_02 = #{momsStoreFg02}


                AND D.MOMS_STORE_FG_03 = #{momsStoreFg03}


                AND D.MOMS_STORE_FG_04 = #{momsStoreFg04}


                AND D.MOMS_STORE_FG_05 = #{momsStoreFg05}

        ) A
ORDER
BY      A.STORE_CD
,       A.PROD_CD
,       A.PROC_DT

